#include <bits/stdc++.h>
using namespace std;
int main(){int K;long long N;cin>>K>>N;vector<long long>a(K);long long hi=0;for(auto&x:a){cin>>x;hi=max(hi,x);}long long lo=1,ans=0;while(lo<=hi){long long m=(lo+hi)/2,c=0;for(auto x:a)c+=x/m;if(c>=N){ans=m;lo=m+1;}else hi=m-1;}cout<<ans<<"\n";}
